<script>

function toggleEdit(){
  document.body.classList.add("editing");
  document.querySelectorAll("[data-field]").forEach(div => {
    const field = div.dataset.field;
    const type = div.dataset.type || "text";
    const dv = div.querySelector(".dv") || div.querySelector(".rv");
    if (!dv) return;
    const raw = dv.dataset.raw || dv.textContent.trim();
    let input;
    if (type === "textarea") {
      input = document.createElement("textarea");
      input.value = raw;
    } else {
      input = document.createElement("input");
      input.type = type === "number" ? "number" : "text";
      input.value = raw;
    }
    input.className = "edit-input";
    input.dataset.field = field;
    dv.style.display = "none";
    dv.parentNode.insertBefore(input, dv.nextSibling);
  });
}

function cancelEdit(){
  document.body.classList.remove("editing");
  document.querySelectorAll(".edit-input").forEach(el => el.remove());
  document.querySelectorAll(".dv, .rv").forEach(el => el.style.display = "");
}

function saveEdit(){
  const fields = {};
  document.querySelectorAll(".edit-input[data-field]").forEach(input => {
    fields[input.dataset.field] = input.value;
  });
  if (Object.keys(fields).length === 0) { cancelEdit(); return; }
  const url = '${updateBaseUrl}&data=' + encodeURIComponent(JSON.stringify(fields));
  window.location.href = url;
}
</script>
