return [{json: {html}}];

function buildNav(userName, userRole, token, baseUrl, currentPage) {
  const ADMIN = ['commercial','responsable','patron','webmaster'];
  const isAdmin = ADMIN.includes(userRole);
  const roleNames = { decoupe_toile:'D\u00e9coupe toile', couture:'Couture', decoupe_armature:'D\u00e9coupe armature', assemblage:'Assemblage', reglage:'R\u00e9glage', emballage:'Emballage', expedition:'Exp\u00e9dition', commercial:'Commercial', responsable:'Responsable', patron:'Patron', webmaster:'Webmaster' };
  const roleDisplay = roleNames[userRole] || userRole;
  const u = (p) => `https://${baseUrl}/webhook/${p}?token=${token}`;
  const a = (page) => currentPage === page ? ' active' : '';
  const links = [];
  links.push({ label:'Accueil', page:'home', href:u('home') });
  links.push({ label:'Production', page:'production', href:u('production') });
  if (isAdmin) links.push({ label:'Validation', page:'validation', href:u('validation') });
  if (isAdmin || userRole==='expedition') links.push({ label:'Dashboard', page:'dashboard', href:u('dashboard') });
  if (['expedition','responsable','patron','webmaster'].includes(userRole)) links.push({ label:'Exp\u00e9dition', page:'expedition', href:u('expedition') });
  if (isAdmin) links.push({ label:'Import', page:'upload', href:u('upload') });
  if (['responsable','patron','webmaster'].includes(userRole)) links.push({ label:'Compta', page:'comptabilite', href:u('comptabilite') });
  if (userRole==='webmaster') links.push({ label:'Utilisateurs', page:'users', href:u('users') });
  const linksHtml = links.map(l => `<a href="${l.href}" class="nav-link${a(l.page)}">${l.label}</a>`).join('');
  return `<nav class="main-nav">
    <a class="nav-brand" href="${u('home')}">MON USINE</a>
    <div class="nav-links">${linksHtml}</div>
    <div class="nav-user">
      <span class="nav-uname">${userName}</span>
      <span class="nav-urole">${roleDisplay}</span>
      <a class="nav-logout" href="https://${baseUrl}/webhook/login">D\u00e9connexion</a>
    </div>
  </nav>`;
}

const items = $input.all();
const params = $('Check Role Permission').first().json;
const token = params.token;
const userName = params.nom_complet;
const userRole = params.role;
const baseUrl = $('Webhook Validation').first().json.headers?.host || 'localhost';
const fmtIso = (s) => s ? s.replace(/\d{4}-\d{2}-\d{2}T[\d:.]+[+-]\d{2}:\d{2}/g, m => { const d = new Date(m); return isNaN(d) ? m : d.toLocaleDateString('fr-FR'); }) : s;

const products = items.filter(i => i.json && i.json.id).map(i => {
  const f = i.json.fields || i.json;
  return {
    id: f.produit_id || i.json.id,
    designation: f.Designation || 'N/A',
    categorie: f.Categorie || '-',
    client: i.json._client_nom || 'N/A',
    facture: i.json._facture_num || 'N/A',
    largeur: f.Largeur_mm || '',
    hauteur: f.Hauteur_mm || '',
    avancee: f['avanc\u00e9e'] || f.avancee || '',
    couleur_toile: f.Couleur_toile || '',
    couleur_armature: f.Couleur_armature || '',
    moteur: f.Moteur || '',
    prix: f.Prix_total_TTC || '-',
    statut: f.statut_validation || 'En attente',
    score: f.confidence_score ?? '',
    remarque: f.Remarque || ''
  };
});

const count = products.length;
const pendingCount = products.filter(p => p.statut === 'En attente').length;
const validatedCount = products.filter(p => p.statut === 'Valid\u00e9').length;
const rejectedCount = products.filter(p => p.statut === 'Rejet\u00e9').length;

// Build table rows with data attributes for filtering
let rowsHtml = '';
if (count === 0) {
  rowsHtml = '<tr><td colspan="12" class="empty">Aucune commande</td></tr>';
} else {
  products.forEach(p => {
    const url = `https://${baseUrl}/webhook/validation?bon_id=${encodeURIComponent(p.id)}&token=${token}`;
    const desig = p.designation.length > 30 ? p.designation.substring(0, 30) + '...' : p.designation;

    let stCls = 'st-wait';
    let stText = 'En attente';
    if (p.statut === 'Valid\u00e9') { stCls = 'st-ok'; stText = 'Valid\u00e9'; }
    else if (p.statut === 'Rejet\u00e9') { stCls = 'st-rej'; stText = 'Rejet\u00e9'; }

    const printBtn = p.statut === 'Valid\u00e9' ? ' <a href="https://' + baseUrl + '/webhook/bon-production?bon_id=' + encodeURIComponent(p.id) + '&token=' + token + '" class="act-btn" target="_blank" title="Bon production">\u{1F5A8}</a>' : '';

    // Score badge
    let scoreTd = '';
    if (p.score !== '' && p.score !== undefined) {
      const sc = Number(p.score);
      const scCol = sc >= 80 ? '#059669' : (sc >= 50 ? '#d97706' : '#dc2626');
      scoreTd = '<span class="score" style="color:' + scCol + '">' + sc + '%</span>';
    }

    // Dims compact
    let dims = '';
    const parts = [];
    if (p.largeur) parts.push(p.largeur);
    if (p.hauteur) parts.push(p.hauteur);
    if (p.avancee) parts.push(p.avancee);
    dims = parts.join(' \u00d7 ');

    rowsHtml += '<tr data-statut="' + p.statut + '" data-search="' + (p.id + ' ' + p.designation + ' ' + p.client + ' ' + p.facture + ' ' + p.categorie).toLowerCase() + '">';
    rowsHtml += '<td><a href="' + url + '">' + fmtIso(p.id) + '</a></td>';
    rowsHtml += '<td class="td-desig">' + fmtIso(desig) + '</td>';
    rowsHtml += '<td>' + p.categorie + '</td>';
    rowsHtml += '<td>' + p.client + '</td>';
    rowsHtml += '<td>' + p.facture + '</td>';
    rowsHtml += '<td class="td-dim">' + dims + '</td>';
    rowsHtml += '<td class="hide-md">' + (p.couleur_toile || '-') + '</td>';
    rowsHtml += '<td class="td-prix">' + p.prix + ' \u20ac</td>';
    rowsHtml += '<td>' + scoreTd + '</td>';
    rowsHtml += '<td><span class="st-badge ' + stCls + '">' + stText + '</span></td>';
    rowsHtml += '<td class="td-acts"><a href="' + url + '" class="act-btn">Voir</a>' + printBtn + '</td>';
    if (p.remarque) rowsHtml += '<!-- rem:' + p.remarque.substring(0, 50).replace(/--/g, '') + ' -->';
    rowsHtml += '</tr>';
  });
}

