<script>
var currentFilter = 'all';
var currentSearch = '';

function filterStatus(status) {
  currentFilter = status;
  document.querySelectorAll('.tab').forEach(t => t.classList.toggle('active', t.dataset.filter === status));
  applyFilters();
}

function doSearch() {
  currentSearch = document.getElementById('searchInput').value.toLowerCase().trim();
  applyFilters();
}

function applyFilters() {
  var rows = document.querySelectorAll('#tableBody tr');
  rows.forEach(function(row) {
    var matchStatus = currentFilter === 'all' || row.dataset.statut === currentFilter;
    var matchSearch = !currentSearch || (row.dataset.search && row.dataset.search.indexOf(currentSearch) >= 0);
    row.classList.toggle('hidden', !(matchStatus && matchSearch));
  });
}
